// filter: selecionando alunos aprovados
interface Aluno {
  nome: string;
  nota: number;
}

const turma: Aluno[] = [
  { nome: "Ana", nota: 9 },
  { nome: "Bruno", nota: 5 },
  { nome: "Clara", nota: 8 }
];

const aprovados: Aluno[] = turma.filter(
  (a: Aluno): boolean => a.nota >= 6
);

console.log(`Aprovados: ${aprovados.length}`);
// Aprovados: 2

// map: extraindo só os nomes
interface Produto {
  nome: string;
  preco: number;
}

const loja: Produto[] = [
  { nome: "Caderno", preco: 15 },
  { nome: "Caneta", preco: 4 },
  { nome: "Mochila", preco: 120 }
];

const nomes: string[] = loja.map(
