);

console.log(nomes);
// ["Caderno", "Caneta", "Mochila"]

// Encadeando filter + map
interface Produto {
  nome: string;
  preco: number;
}

const produtos: Produto[] = [
  { nome: "Teclado", preco: 200 },
  { nome: "Mouse", preco: 80 },
  { nome: "Monitor", preco: 900 },
  { nome: "Webcam", preco: 150 }
];

const carosNomes: string[] = produtos
  .filter((p: Produto): boolean => p.preco > 100)
  .map((p: Produto): string => `${p.nome} (R$${p.preco})`);

console.log(carosNomes);
// ["Teclado (R$200)", "Monitor (R$900)", "Webcam (R$150)"]

// Somando valores com for...of
interface Compra {
  item: string;
  valor: number;
}

const compras: Compra[] = [
  { item: "Arroz", valor: 22 },
  { item: "Feijão", valor: 9 },
  { item: "Macarrão", valor: 6 }
];

let total: number = 0;
for (const compra of compras) {
  total += compra.valor;
}

console.log(`Total: R$${total}`);
// Total: R$37

// Array de objetos com booleanos
interface Tarefa {
  descricao: string;
  concluida: boolean;
}

const tarefas: Tarefa[] = [
  { descricao: "Estudar TypeScript", concluida: true },
  { descricao: "Fazer exercícios", concluida: false },
  { descricao: "Ler um livro", concluida: true }
];

const pendentes: Tarefa[] = tarefas.filter(
  (t: Tarefa): boolean => !t.concluida
);

console.log(`Pendentes: ${pendentes.length}`);
// Pendentes: 1

// O padrão: acumular valores num loop
const precos: number[] = [10, 20, 30];
let soma: number = 0;

for (const preco of precos) {
  soma += preco;
}

console.log(`Soma: ${soma}`);
// Soma: 60

// Acumulando com multiplicação (mesmo padrão do exercício)
interface Produto {
  nome: string;
  qtd: number;
  preco: number;
}

const lista: Produto[] = [
  { nome: "Arroz", qtd: 2, preco: 22 },
  { nome: "Feijão", qtd: 3, preco: 9 }
];

let total: number = 0;
for (const p of lista) {
  total += p.qtd * p.preco;
}

console.log(`Total: R$${total}`);
// Total: R$71 (44 + 27)

// Erro: somando só o valor unitário
interface Item {
  nome: string;
  quantidade: number;
  valor: number;
}

const inv: Item[] = [
  { nome: "Poção", quantidade: 5, valor: 10 },
  { nome: "Espada", quantidade: 1, valor: 150 }
];

let errado: number = 0;
for (const i of inv) {
  errado += i.valor;
}
console.log(`Errado: ${errado}`);
// Errado: 160 (somou só preços unitários, ignorou quantidade)

// Versão correta do cálculo
interface Item {
  nome: string;
  quantidade: number;
  valor: number;
}

const inv: Item[] = [
  { nome: "Poção", quantidade: 5, valor: 10 },
  { nome: "Espada", quantidade: 1, valor: 150 }
];

let correto: number = 0;
for (const i of inv) {
  correto += i.quantidade * i.valor;
}
console.log(`Correto: ${correto}`);
// Correto: 200 (50 + 150)

// Mostrando subtotais para conferir
interface Item {
  nome: string;
  quantidade: number;
  valor: number;
}

const itens: Item[] = [
  { nome: "A", quantidade: 3, valor: 10 },
  { nome: "B", quantidade: 2, valor: 25 }
];

let total: number = 0;
for (const item of itens) {
  const subtotal: number = item.quantidade * item.valor;
  console.log(`${item.nome}: ${item.quantidade} x ${item.valor} = ${subtotal}`);
  total += subtotal;
}
console.log(`Total: ${total}`);
// A: 3 x 10 = 30
// B: 2 x 25 = 50
// Total: 80

// Usando o operador +=
let valor: number = 0;
valor += 50;
console.log(valor);
valor += 150;
console.log(valor);
valor += 40;
console.log(valor);
// 50
// 200
