// Filtrando por propriedade booleana
interface Email {
  assunto: string;
  lido: boolean;
}

const inbox: Email[] = [
  { assunto: "Reunião amanhã", lido: true },
  { assunto: "Promoção", lido: false },
  { assunto: "Nota fiscal", lido: false }
];

for (const email of inbox) {
  if (!email.lido) {
    console.log(`📩 ${email.assunto}`);
  }
}
