// 📩 Nota fiscal

// Função que recebe array de objetos
interface Aluno {
  nome: string;
  nota: number;
}

function listarAprovados(alunos: Aluno[]): void {
  for (const aluno of alunos) {
    if (aluno.nota >= 6) {
      console.log(`✅ ${aluno.nome}: ${aluno.nota}`);
    }
  }
}

const turma: Aluno[] = [
  { nome: "Ana", nota: 9 },
  { nome: "Bruno", nota: 4 },
  { nome: "Clara", nota: 7 }
];

listarAprovados(turma);
// ✅ Ana: 9
// ✅ Clara: 7

// if (booleano) — sem === true
const ativo: boolean = true;

if (ativo) {
  console.log("Está ativo!");
}
// Está ativo!

// Equivalente (mas redundante):
if (ativo === true) {
  console.log("Também funciona, mas é desnecessário");
}

// Erro: comparando booleano com string
const favorito: boolean = true;

console.log(favorito === true);
console.log(favorito === "true" as any);
// true
// false — "true" (string) !== true (boolean)

// Usando .filter() como alternativa
interface Contato {
  nome: string;
  favorito: boolean;
}

const lista: Contato[] = [
  { nome: "Ana", favorito: true },
  { nome: "Bob", favorito: false },
  { nome: "Carol", favorito: true }
];

const favs: Contato[] = lista.filter(
  (c: Contato): boolean => c.favorito
);

for (const c of favs) {
  console.log(`⭐ ${c.nome}`);
}
// ⭐ Ana
// ⭐ Carol

// Função reutilizável com diferentes dados
interface Tarefa {
  titulo: string;
  concluida: boolean;
}

function mostrarPendentes(tarefas: Tarefa[]): void {
  for (const t of tarefas) {
    if (!t.concluida) {
      console.log(`⬜ ${t.titulo}`);
    }
  }
}

const casa: Tarefa[] = [
  { titulo: "Lavar louça", concluida: true },
  { titulo: "Varrer", concluida: false }
];

mostrarPendentes(casa);
// ⬜ Varrer

